using System.Windows.Forms;

public class MainForm : Form
{
    private readonly StatusStrip _statusStrip;

    public MainForm()
    {
        _statusStrip = new StatusStrip();
        // .NET 9: StatusStrip no longer defaults to ToolStripRenderMode.System.
        // Set explicitly to preserve the .NET 8 visual appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        Controls.Add(_statusStrip);
    }
}

using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class PropertyEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(System.ComponentModel.ITypeDescriptorContext? context)
        => UITypeEditorEditStyle.DropDown;

    public override object? EditValue(
        System.ComponentModel.ITypeDescriptorContext? context,
        IServiceProvider? provider,
        object? value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;

        if (editorService is null)
            return value;

        // .NET 9: DropDownControl parameter changed from nullable to non-nullable.
        // Guard against passing null to avoid NullReferenceException / warning.
        var control = CreateDropDownControl(value);
        if (control is not null)
        {
            editorService.DropDownControl(control);
            value = GetValueFromControl(control);
        }

        return value;
    }

    private static Control? CreateDropDownControl(object? currentValue)
    {
        // Return null when no meaningful editor control can be created.
        if (currentValue is null)
            return null;

        var listBox = new ListBox();
        listBox.Items.Add(currentValue);
        return listBox;
    }

    private static object? GetValueFromControl(Control control)
    {
        if (control is ListBox listBox && listBox.SelectedItem is not null)
            return listBox.SelectedItem;
        return null;
    }
}

